import { useNavigate } from 'react-router-dom';

function Products() {
  const navigate = useNavigate();
  const [products, setProducts] = useState([]);

  useEffect(() => {
    axios.get('http://localhost:5000/api/products')
      .then((res) => setProducts(res.data))
      .catch((err) => console.error("Failed to fetch products:", err));
  }, []);

  const handleCardClick = (id) => {
    navigate(`/products/${id}`);
  };

  const handleAddToCart = (product) => {
    // TODO: You can connect this to Redux or LocalStorage
    console.log("Added to cart:", product);
  };

  const renderSection = (title, items) => (
    <>
      <h1 className="section-title">{title}</h1>
      <div className="product-grid">
        {items.map(item => (
          <div
            key={item._id}
            className="product-card"
            onClick={() => handleCardClick(item._id)}
          >
            <img src={item.image} alt={item.name} />
            <h3>{item.name}</h3>
            <p>₹{item.price}</p>
            <button
              className="add-to-cart-btn"
              onClick={(e) => {
                e.stopPropagation(); // Prevent card click
                handleAddToCart(item);
              }}
            >
              🛒 Add to Cart
            </button>
          </div>
        ))}
      </div>
    </>
  );

  const shirts = products.filter(p => p.category === 'shirt');
  const pants = products.filter(p => p.category === 'pants');
  const innerwears = products.filter(p => p.category === 'innerwear');

  return (
    <div className="products-container">
      {renderSection('🧥 Shirts', shirts)}
      {renderSection('👖 Pants', pants)}
      {renderSection('🩲 Innerwear', innerwears)}
    </div>
  );
}
